import{_ as a,v as l,b as e,R as s}from"./chunks/framework.caa0fbaf.js";const m=JSON.parse('{"title":"Android 命令行工具","description":"","frontmatter":{},"headers":[],"relativePath":"Android/android-adb/index.md","filePath":"Android/android-adb/index.md"}'),t={name:"Android/android-adb/index.md"},i=s(`<p>[TOC]</p><h1 id="android-命令行工具" tabindex="-1">Android 命令行工具 <a class="header-anchor" href="#android-命令行工具" aria-label="Permalink to &quot;Android 命令行工具&quot;">​</a></h1><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">// adb 连接不上时</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">netstat -aon | findstr &quot;5307&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">// 找到占用 5307 端口的进程 ID，比如 13440</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">taskkill /pid 13440 /f</span></span>
<span class="line"><span style="color:#A6ACCD;">// 杀死该进程</span></span></code></pre></div><h2 id="adb-shell" tabindex="-1">adb shell <a class="header-anchor" href="#adb-shell" aria-label="Permalink to &quot;adb shell&quot;">​</a></h2><ul><li>adb shell</li><li>adb devices</li><li>adb -s [device-name] shell</li></ul><h3 id="展示当前前台界面所属-activity" tabindex="-1">展示当前前台界面所属 Activity <a class="header-anchor" href="#展示当前前台界面所属-activity" aria-label="Permalink to &quot;展示当前前台界面所属 Activity&quot;">​</a></h3><ul><li><p>adb shell dumpsys activity | grep &quot;mResume&quot; // Android 12 及以下系统版本有效，显示当前界面类名</p></li><li><p>adb shell dumpsys activity | grep &quot;mResume&quot; | awk &#39;{printf $4}&#39; // Android 12 及以下</p></li><li><p>adb shell dumpsys activity | grep &quot;topResumedActivity&quot; | awk &#39;{printf $3}&#39; // Android 13</p></li><li><p>adb shell dumpsys activity activities // 查看 Activity 组件信息</p></li><li><p>adb shell dumpsys activity services // 查看 Service 组件信息</p></li><li><p>adb shell dumpsys activity providers // 产看 ContentProvider 组件信息</p></li><li><p>adb shell dumpsys activity broadcasts // 查看 BroadcastReceiver 信息</p></li><li><p>adb shell dumpsys activity intents // 查看 Intent 信息</p></li><li><p>adb shell dumpsys activity processes // 查看进程信息</p></li><li><p>// 查看运行中的服务</p></li><li><p>adb shell dumpsys activity services | grep ServiceRecord | awk &#39;{print $4}&#39; | sed &#39;s/}//1g&#39;</p></li><li><p>adb shell am start -a android.intent.action.VIEW -d &quot;<a href="http://192.168.101.4/get_data.xml" target="_blank" rel="noreferrer">http://192.168.101.4/get_data.xml</a>&quot; // 浏览器打开页面</p></li><li><p>adb shell df // 查看存储空间情况</p></li></ul><h2 id="连接-wifi" tabindex="-1">连接 WiFi <a class="header-anchor" href="#连接-wifi" aria-label="Permalink to &quot;连接 WiFi&quot;">​</a></h2><ol><li>开启网络 ADB 调试</li></ol><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">//</span></span>
<span class="line"><span style="color:#FFCB6B;">adb</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">tcpip</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">5555</span></span>
<span class="line"><span style="color:#FFCB6B;">//</span><span style="color:#A6ACCD;"> </span></span>
<span class="line"><span style="color:#FFCB6B;">adb</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">shell</span></span>
<span class="line"><span style="color:#FFCB6B;">setprop</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">service.adb.tcp.port</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">5555</span></span></code></pre></div><ol start="2"><li>连接</li></ol><ul><li>adb connect 192.168.20.162:5555</li></ul><h2 id="emulator" tabindex="-1">emulator <a class="header-anchor" href="#emulator" aria-label="Permalink to &quot;emulator&quot;">​</a></h2><ul><li>emulator @emalator-name</li></ul><blockquote><p>启动模拟器 e.g. emulator @GalaxyNexusAPI21</p></blockquote><h2 id="screen" tabindex="-1">screen <a class="header-anchor" href="#screen" aria-label="Permalink to &quot;screen&quot;">​</a></h2><ol><li><p>获取 Android 设备屏幕分辨率 adb shell wm size</p></li><li><p>获取 Android 设备屏幕密度 adb shell wm density</p></li><li><p>修改屏幕像素密度 adb shell wm resize 1920*1080 adb shell wm size 540x960</p></li><li><p>重置屏幕尺寸大小 adb shell wm size reset</p></li><li><p>设置屏幕 dpi（常用的 dpi 有 160 mdpi, 240 hdpi, 320 xhdpi, 480 xxhdpi） adb shell wm density 320</p></li><li><p>重置可用 dpi 如下命令 adb shell wm density reset</p></li><li><p>录屏 adb shell screenrecord sdcard/test01.mp4 adb pull sdcard/test01.mp4</p></li><li><p>截屏 adb shell screencap -p sdcard/screen.png adb pull sdcard/screen.png</p></li><li><p>是否允许旋转屏幕</p></li></ol><ul><li>set</li></ul><p>adb shell content insert --uri content://settings/system --bind name:s:accelerometer_rotation --bind value:i:1 // 0 - 禁止 1 - 允许 或 adb shell settings put system accelerometer_rotation 1</p><p>adb shell content insert --uri content://settings/system --bind name:s:user_rotation --bind value:i:1 // 0 - 3 或 adb shell settings put system user_rotation 1</p><ul><li>get</li></ul><p>adb shell settings get system accelerometer_rotation # 0 - 不支持旋转 1 - 支持旋转 adb shell settings get system user_rotation # 0 - 竖屏 1 - 横屏</p><h2 id="其它" tabindex="-1">其它 <a class="header-anchor" href="#其它" aria-label="Permalink to &quot;其它&quot;">​</a></h2><ol start="9"><li><p>输入文字 adb shell input text &quot;blabla&quot;</p></li><li><p>文件传输 adb pull sdcard/xxx adb push local-target-file sdcard/xxx</p></li><li><p>启动 APP $ adb shell am start -n &quot;com.xxx.intelligent.uat/com.xxx.retail.ui.activity.GuideActivity&quot; -a android.intent.action.MAIN -c android.intent.category.LAUNCHER</p></li><li><p>导出 APK adb shell pm list package // com.DeviceTest 是我要导出的 APP 包名 adb shell pm path com.DeviceTest // APP 在手机中的存放路径：/system/priv-app/DeviceTest/DeviceTest.apk // APP 导出的目标 apk 在 PC 端的存放路径：C:\\Users\\Administrator\\Desktop<br> adb pull /system/priv-app/DeviceTest/DeviceTest.apk C:\\Users\\Administrator\\Desktop\\</p></li><li><p>logcat 查看日志</p></li></ol><p>adb shell &quot;ps | grep com.xxx.intelligent&quot; - 查看进程号 adb logcat | grep 进程号</p><ol start="14"><li>跳转桌面</li></ol><p>adb shell input keyevent 3</p><ol start="15"><li>监听屏幕点击</li></ol><p>adb shell getevent | grep -e &quot;0035&quot; -e &quot;0036&quot;</p><ol start="16"><li>查看架构</li></ol><p>adb shell getprop ro.product.cpu.abi</p><ol start="17"><li>杀死 app</li></ol><p>$ adb shell am force-stop cn.xxx.facepay</p><ol start="18"><li>查看 app 占用运行内存</li></ol><p>$ adb shell dumpsys meminfo cn.xxx.facepay</p><ol start="19"><li>查看 app version name</li></ol><p>$ adb shell &quot;dumpsys package $packageName | grep versionName&quot;</p>`,37),p=[i];function n(o,r,d,c,u,h){return l(),e("div",null,p)}const y=a(t,[["render",n]]);export{m as __pageData,y as default};
